### 3. Blocking 발생 시 실행 로직 (`CompactionOrchestrator.blockAtHardLimit`)

```typescript
// compaction-orchestrator.ts L550-604
async blockAtHardLimit(
  historyOrAdditionalTokens: CompactionHistoryLike | number,
  additionalTokensOrPhase: number | CompactionPhase,
  maybePhase?: CompactionPhase
): Promise<boolean> {
  // 인자 파싱 (오버로드 지원)
  const hasHistoryArg = isHistoryLike(historyOrAdditionalTokens);
  const history = this.resolveHistory(
    hasHistoryArg ? historyOrAdditionalTokens : undefined
  );
  if (!history) {
    return Promise.resolve(false);  // history가 없으면 false
  }

  const additionalTokens = hasHistoryArg
    ? (additionalTokensOrPhase as number)
    : (historyOrAdditionalTokens as number);
  const phase = (
    hasHistoryArg ? maybePhase : additionalTokensOrPhase
  ) as CompactionPhase;

  // STEP 1: Hard limit 체크
  const blocking = this.isAtHardLimit(history, additionalTokens, phase);
  if (!blocking) {
    return false;  // → hard limit이 아니면 즉시 반환
  }

  // STEP 2 & 5: Blocking 상태 callback (UI 렌더링용)
  this.callbacks.onBlockingChange?.(true);
  try {
    // STEP 3: Prune 시도
    const pruneHandled = await this.tryPruneBeforeOverflow(
      history,
      additionalTokens,
      phase
    );

    // STEP 4: Prune 실패 시 → Overflow 처리
    if (!pruneHandled) {
      await this.handleOverflow(new Error("context_limit_hard_block"));
    }
  } finally {
    // STEP 5: Blocking 해제
    this.callbacks.onBlockingChange?.(false);
  }

  // STEP 6 & FINAL: Hard limit 지속 여부 확인
  if (this.isAtHardLimit(history, additionalTokens, phase)) {
    this.callbacks.onStillExceeded?.();  // 경고 UI 표시
  }

  return true;  // blocking이 발생했음을 반환
}
```

